import DeleteOutlineRoundedIcon from '@mui/icons-material/DeleteOutlineRounded';
import { Box, CardMedia, Divider, IconButton, Typography, Stack } from "@mui/material";

const WishItem = ({ poster, removeFromWishList, id, name, price }) => {

    return (
        <Box sx={{ py: 2 }}>
            <Stack direction="row" spacing={2} alignItems="center">
                <Box sx={{ width: 80, height: 100, flexShrink: 0, borderRadius: '12px', overflow: 'hidden' }}>
                    <CardMedia
                        image={poster}
                        component="img"
                        alt={name}
                        sx={{ width: '100%', height: '100%', objectFit: 'cover' }}
                    />
                </Box>

                <Box sx={{ flexGrow: 1 }}>
                    <Typography 
                        variant="body2" 
                        component="a" 
                        href={'/' + id} 
                        sx={{ 
                            color: 'white', 
                            textDecoration: 'none', 
                            fontWeight: 700,
                            display: 'block',
                            mb: 0.5,
                            '&:hover': { color: 'primary.main' }
                        }}
                    >
                        {name.length > 50 ? name.slice(0, 50) + "..." : name}
                    </Typography>
                    
                    <Typography variant="body2" sx={{ fontWeight: 800, color: 'primary.main' }}>
                        {price} ₴
                    </Typography>
                </Box>

                <IconButton
                    onClick={() => removeFromWishList(id)}
                    sx={{ color: 'rgba(255,255,255,0.3)', '&:hover': { color: 'error.main' } }}
                >
                    <DeleteOutlineRoundedIcon />
                </IconButton>
            </Stack>
            <Divider sx={{ mt: 2, opacity: 0.5 }} />
        </Box>
    );
};

export default WishItem;
